import random, math

def welzl(P):
    def trivial(R):
        if len(R) == 0: return (0, 0, 0)
        if len(R) == 1: return (R[0][0], R[0][1], 0)
        if len(R) == 2:
            x1, y1 = R[0]; x2, y2 = R[1]
            cx, cy = (x1+x2)/2, (y1+y2)/2
            d = math.hypot(x2-x1, y2-y1)
            return (cx, cy, d/2)
        # 3 points → circumcircle
        (x1,y1),(x2,y2),(x3,y3) = R[0],R[1],R[2]
        d = 2*(x1*(y2-y3) + x2*(y3-y1) + x3*(y1-y2))
        if abs(d) < 1e-12: return (0, 0, float('inf'))
        ux = ((x1*x1+y1*y1)*(y2-y3) + (x2*x2+y2*y2)*(y3-y1) + (x3*x3+y3*y3)*(y1-y2))/d
        uy = ((x1*x1+y1*y1)*(x3-x2) + (x2*x2+y2*y2)*(x1-x3) + (x3*x3+y3*y3)*(x2-x1))/d
        r = math.hypot(ux-x1, uy-y1)
        return (ux, uy, r)

    def solve(P, R):
        if not P or len(R) == 3:
            return trivial(R)
        p = P[-1]
        P = P[:-1]
        c = solve(P, R)
        if point_in_circle(p[0], p[1], c[0], c[1], c[2] + 1e-9):
            return c
        return solve(P, R + [p])

    random.shuffle(P)
    cx, cy, r = solve(P, [])
    return (cx, cy, r)

